pub enum MemoryType {
    Structural,
    Decisional,
    #[default]
    Episodic,
    Analytical,
    Procedural,
}
impl MemoryType {
    /// All memory type variants, in a fixed order for deterministic iteration.
    pub const ALL: [MemoryType; 5] = [
        MemoryType::Structural,
        MemoryType::Decisional,
        MemoryType::Episodic,
        MemoryType::Analytical,
        MemoryType::Procedural,
    ];
}
